                    />
                    <button 
                        type="submit" 
                        disabled={loading || !company}
                        className="bg-primary-600 hover:bg-primary-500 disabled:opacity-50 text-white px-4 py-2 rounded-lg font-medium transition-colors whitespace-nowrap"
                    >
                        {loading ? 'Running...' : 'Run Forecast'}
