                                        <span className="w-1.5 h-1.5 bg-indigo-500 rounded-full mr-1.5"></span>
                                        {comp.lastEarningsReport}
                                    </span>
                                )}
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </div>

      </div>
    </div>
  );
};

