  return (
    <div className="w-14 h-14 rounded-xl bg-white shadow-lg shadow-indigo-900/50 shrink-0 overflow-hidden flex items-center justify-center">
       <img 
         src={logoUrl} 
         alt={`${ticker} logo`} 
