          {isPositive ? <ArrowTrendingUp className="w-3 h-3 mr-1" /> : isNeutral ? null : <ArrowTrendingDown className="w-3 h-3 mr-1" />}
          {metric.change > 0 ? '+' : ''}{metric.change}%
