                 </div>

                 {/* Platform Description */}
                 <div className="w-full mb-16 bg-gradient-to-b from-slate-800/40 to-slate-900/40 border border-slate-800 rounded-2xl p-6 text-left relative overflow-hidden backdrop-blur-sm shadow-xl">
